// マーケティング施策 → Firebaseサービスのマッピング
const useCaseMapping = {
  // プッシュ通知でチャーンユーザーを呼び戻す施策
  reengagementPush: '',

  // アプリのクラッシュを検知してUX改善の優先度を決める
  crashDetection: '',

  // オンボーディングのAパターンとBパターンの効果を比較する
  onboardingAbTest: '',

  // ユーザーの行動データ（DAU・イベント）を分析する
  behaviorAnalytics: '',

  // キャンペーン中だけ特定バナーを表示する（コード変更なし）
  remoteFeatureToggle: ''
};

// 確認出力（変更不要）
const services = [
  'Firebase Cloud Messaging',
  'Firebase Crashlytics',
  'Firebase A/B Testing',
  'Firebase Analytics',
  'Firebase Remote Config'
];

Object.entries(useCaseMapping).forEach(([useCase, service]) => {
  const isValid = services.includes(service);
  console.log(`${useCase}: ${service} ${isValid ? '✓' : '× (未設定または誤り)'}`);
});

